#include<bits/stdc++.h>
using namespace std;
int cnt[1000010],c[150010];
int blksiz;
struct node
{
    int l,r,tim,id;
    bool operator<(const node&b)const
    {
        if(l/blksiz!=b.l/blksiz)
        {
            return l>b.l;
        }
        if(r/blksiz!=b.r/blksiz)
        {
            return r>b.r;
        }
        return tim>b.tim;
    }
}q[150010];
struct modify
{
    int pos,val;
}p[300010];
long long res,ans[150010];
void add(int x)
{
    if(cnt[x]==0)
    {
        res++;
    }
    cnt[x]++;
}
void del(int x)
{
    cnt[x]--;
    if(cnt[x]==0)
    {
        res--;
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    blksiz=cbrt(n)*cbrt(n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
    }
    int k=0,now=0;
    for(int i=1;i<=m;i++)
    {
        char op;
        int x,y;
        cin>>op;
        scanf("%d%d",&x,&y);
        if(op=='Q')
        {
            q[++k].l=x;
            q[k].r=y;
            q[k].id=k;
            q[k].tim=now;
        }
        else
        {
            p[++now].pos=x;
            p[now].val=y;
        }
    }
    sort(q+1,q+1+k);
    int l=1,r=0,t=0;
    for(int i=1;i<=k;i++)
    {
        while(l>q[i].l)
        {
            add(c[--l]);
        }
        while(l<q[i].l)
        {
            del(c[l++]);
        }
        while(r<q[i].r)
        {
            add(c[++r]);
        }
        while(r>q[i].r)
        {
            del(c[r--]);
        }
        while(t<q[i].tim)
        {
            t++;
            if(p[t].pos>=l&&p[t].pos<=r)
            {
                add(p[t].val);
                del(c[p[t].pos]);
            }
            swap(c[p[t].pos],p[t].val);
        }
        while(t>q[i].tim)
        {
            if(p[t].pos>=l&&p[t].pos<=r)
            {
                add(p[t].val);
                del(c[p[t].pos]);
            }
            swap(c[p[t].pos],p[t].val);
            t--;
        }
        ans[q[i].id]=res;
    }
    for(int i=1;i<=k;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
